import Image from "next/image";
import Link from "next/link";

export default function Software() {
  return (
    <div className="flex flex-col gap-8 py-10" data-theme="theme-software">
      {/* Header */}
      <div className="text-center">
        <h1 className="text-4xl font-bold mb-4 text-info">Software</h1>
        <p className="text-xl">Soluções tecnológicas com propósito.</p>
      </div>

      {/* Projects Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        {/* Project 1: Mass Diária */}
        <div className="card bg-base-100 border-4 border-black shadow-[8px_8px_0_0_rgba(0,0,0,1)] rounded-none">
          <div className="card-body">
            <h2 className="card-title text-xl text-info">Mass Diária</h2>
            <p>Aplicativo para acompanhamento da liturgia diária.</p>
            <div className="card-actions justify-end mt-4">
               <button className="btn btn-info btn-sm border-2 border-black rounded-none">Ver Detalhes</button>
            </div>
          </div>
        </div>

        {/* Project 2: Recanto */}
        <div className="card bg-base-100 border-4 border-black shadow-[8px_8px_0_0_rgba(0,0,0,1)] rounded-none">
          <div className="card-body">
            <h2 className="card-title text-xl text-info">Recanto</h2>
            <p>Sistema de gestão para casas de retiro.</p>
            <div className="card-actions justify-end mt-4">
               <button className="btn btn-info btn-sm border-2 border-black rounded-none">Ver Detalhes</button>
            </div>
          </div>
        </div>

         {/* Project 3: wwebjs-rest-api */}
        <div className="card bg-base-100 border-4 border-black shadow-[8px_8px_0_0_rgba(0,0,0,1)] rounded-none">
          <div className="card-body">
            <h2 className="card-title text-xl text-info">wwebjs-rest-api</h2>
            <p>API REST para integração com WhatsApp Web.</p>
            <div className="card-actions justify-end mt-4">
               <button className="btn btn-info btn-sm border-2 border-black rounded-none">Ver Detalhes</button>
            </div>
          </div>
        </div>
      </div>

      {/* Animation Showcase Section */}
      <div className="mt-12 p-8 border-4 border-black bg-base-200 rounded-none relative overflow-hidden group">
        <h2 className="text-2xl font-bold mb-6 text-center">Showcase de Animações</h2>
        
        <div className="flex justify-center gap-8 flex-wrap">
            {/* Bouncing Ball */}
            <div className="w-16 h-16 bg-primary border-2 border-black animate-bounce flex items-center justify-center text-white font-bold shadow-[4px_4px_0_0_rgba(0,0,0,1)]">
                8-BIT
            </div>

            {/* Spinning Square */}
            <div className="w-16 h-16 bg-secondary border-2 border-black animate-spin flex items-center justify-center text-white font-bold shadow-[4px_4px_0_0_rgba(0,0,0,1)]">
                PIXEL
            </div>

            {/* Pulse Circle */}
            <div className="w-16 h-16 bg-accent border-2 border-black animate-pulse rounded-full flex items-center justify-center text-white font-bold shadow-[4px_4px_0_0_rgba(0,0,0,1)]">
                DEV
            </div>
        </div>
        
        <p className="text-center mt-8 text-sm opacity-70">
            * Estas animações são renderizadas com CSS puro e Tailwind.
        </p>
      </div>

      {/* Back Button */}
      <div className="text-center mt-8">
        <Link href="/" className="btn btn-ghost hover:bg-transparent hover:underline">
          ← Voltar para Home
        </Link>
      </div>
    </div>
  );
}
